<span class="line"><span style="color:#A6ACCD;"># yarn add rimraf cpr make</span><span style="color:#89DDFF;">-</span><span style="color:#A6ACCD;">dir</span><span style="color:#89DDFF;">-</span><span style="color:#A6ACCD;">cli </span><span style="color:#89DDFF;">-</span><span style="color:#A6ACCD;">D</span></span>
