<span class="line"><span style="color:#A6ACCD;">+    </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C792EA;">postcover</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">npm-run-all cover:archive --parallel cover:serve cover:open</span><span style="color:#89DDFF;">&quot;</span></span>
